import{_ as o,o as r,c as e,ag as l}from"./chunks/framework.BbyMWZAR.js";const c=JSON.parse('{"title":"常见 HTTP 状态码：1xx / 2xx / 3xx / 4xx / 5xx","description":"","frontmatter":{"title":"常见 HTTP 状态码：1xx / 2xx / 3xx / 4xx / 5xx","difficulty":"medium","tags":["HTTP","状态码"],"estimate":20},"headers":[],"relativePath":"domains/browser/qa/qa-11-http-status-codes.md","filePath":"domains/browser/qa/qa-11-http-status-codes.md","lastUpdated":1783504823000}'),i={name:"domains/browser/qa/qa-11-http-status-codes.md"};function a(s,t,n,d,g,x){return r(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="问答-11-进阶-常见-http-状态码-1xx-2xx-3xx-4xx-5xx" tabindex="-1">问答 11（进阶）：常见 HTTP 状态码：1xx / 2xx / 3xx / 4xx / 5xx <a class="header-anchor" href="#问答-11-进阶-常见-http-状态码-1xx-2xx-3xx-4xx-5xx" aria-label="Permalink to &quot;问答 11（进阶）：常见 HTTP 状态码：1xx / 2xx / 3xx / 4xx / 5xx&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>HTTP 状态码分几类，各类常见状态码有哪些？请重点说明 301 vs 302 vs 307 vs 308、304、401 vs 403、499、502 vs 504。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>分类速览</strong></p><table tabindex="0"><thead><tr><th>类</th><th>含义</th><th>常见</th></tr></thead><tbody><tr><td>1xx</td><td>信息</td><td>100 Continue、101 Switching Protocols、103 Early Hints</td></tr><tr><td>2xx</td><td>成功</td><td>200、201、204、206 Partial Content</td></tr><tr><td>3xx</td><td>重定向</td><td>301、302、303、304、307、308</td></tr><tr><td>4xx</td><td>客户端错误</td><td>400、401、403、404、405、408、409、410、413、415、422、429、499</td></tr><tr><td>5xx</td><td>服务端错误</td><td>500、501、502、503、504</td></tr></tbody></table><p><strong>重定向类</strong></p><ul><li><strong>301 Moved Permanently</strong>：永久重定向。浏览器 / SEO 会缓存，之后直接跳新地址。<strong>方法可能被改为 GET</strong>（历史上 POST → GET 是常见浏览器行为）。</li><li><strong>302 Found</strong>：临时重定向，语义模糊。历史上很多浏览器实现里 302 会把 POST 改为 GET，与规范不完全一致。</li><li><strong>307 Temporary Redirect</strong>：临时重定向，<strong>严格保留原方法和 body</strong>（POST 还是 POST）。</li><li><strong>308 Permanent Redirect</strong>：永久重定向，<strong>严格保留方法</strong>。</li><li>简单口诀：<strong>7 / 8 保留方法，1 / 2 可能变 GET；奇数临时，偶数永久</strong>。</li></ul><p><strong>304 Not Modified</strong></p><ul><li>协商缓存命中，body 为空。浏览器复用本地缓存。</li><li>客户端通常带 <code>If-None-Match</code> / <code>If-Modified-Since</code>。</li></ul><p><strong>401 vs 403</strong></p><ul><li><strong>401 Unauthorized</strong>：<strong>未认证</strong>（没登录或凭证无效）。响应应带 <code>WWW-Authenticate</code> 头指示认证方式。</li><li><strong>403 Forbidden</strong>：<strong>已认证但无权限</strong>（登录了但没资格访问此资源）。</li><li>区分：401 想让你重新登录，403 告诉你「你已经登录了但也没用」。</li></ul><p><strong>404 vs 410</strong></p><ul><li>404：资源不存在（可能只是暂时找不到）。</li><li>410 Gone：资源永久删除，告知搜索引擎不再来。</li></ul><p><strong>499（Nginx 私有）</strong></p><ul><li>客户端主动断开连接，服务端还在处理。</li><li>常见原因：前端超时取消、用户离开页面、上游代理超时。</li><li>不是标准 HTTP 状态码，标准 4xx 里没有。</li></ul><p><strong>5xx</strong></p><ul><li><strong>500 Internal Server Error</strong>：应用抛未处理异常。</li><li><strong>502 Bad Gateway</strong>：网关（Nginx / LB）从上游拿到无效响应。常见于上游进程崩了、连接被重置。</li><li><strong>503 Service Unavailable</strong>：服务暂时不可用（过载 / 维护），可带 <code>Retry-After</code>。</li><li><strong>504 Gateway Timeout</strong>：网关等上游超时。<strong>502 vs 504</strong>：一个是「上游给了坏响应」，一个是「上游没给响应」。</li></ul><p><strong>其它常见</strong></p><ul><li><strong>206 Partial Content</strong>：范围请求（视频拖动、断点续传）成功。</li><li><strong>413 Payload Too Large</strong>：请求体过大。</li><li><strong>415 Unsupported Media Type</strong>：Content-Type 不支持。</li><li><strong>422 Unprocessable Entity</strong>：语法对但业务校验失败（表单验证）。</li><li><strong>429 Too Many Requests</strong>：限流。</li></ul><h2 id="追问-1-post-请求收到-302-会怎么样-为什么推荐用-307-308" tabindex="-1">追问 1：POST 请求收到 302 会怎么样？为什么推荐用 307 / 308？ <a class="header-anchor" href="#追问-1-post-请求收到-302-会怎么样-为什么推荐用-307-308" aria-label="Permalink to &quot;追问 1：POST 请求收到 302 会怎么样？为什么推荐用 307 / 308？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>历史上 HTTP/1.0 里 302 没规定方法保留，很多浏览器实现把 302 的 POST 改成 GET（因为大家「都这么用」），但规范其实要求保留方法。这导致 302 语义不明。</li><li>HTTP/1.1 引入 307（临时）和 308（永久），明确规定 <strong>必须保留原方法和 body</strong>。</li><li>因此对 POST / PUT / DELETE： <ul><li>想让客户端保持方法 → 用 307 / 308。</li><li>想强制变成 GET（比如 POST 完成后跳到详情页） → 用 303 See Other。</li></ul></li><li>API 设计推荐用 307 / 308 / 303，语义清晰不踩坑。</li></ul><h2 id="追问-2-499-出现说明什么-常见排查思路" tabindex="-1">追问 2：499 出现说明什么？常见排查思路？ <a class="header-anchor" href="#追问-2-499-出现说明什么-常见排查思路" aria-label="Permalink to &quot;追问 2：499 出现说明什么？常见排查思路？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>499 是 Nginx 自定义，代表<strong>客户端已断开，服务端还没写完响应</strong>。</li><li>常见来源： <ol><li>前端 <code>AbortController.abort()</code> 或组件卸载取消请求。</li><li>用户切页 / 关闭 tab。</li><li>上游超时时间（浏览器 / 上游代理 / 网关）小于后端处理时间，客户端提前放弃。</li><li>LB / 反向代理超时，先关掉了下游连接。</li></ol></li><li>排查： <ul><li>看后端接口 P99 是否高，客户端可能在等超时后放弃。</li><li>前端是否用了 <code>AbortSignal.timeout(N)</code> 之类主动超时。</li><li>Nginx 的 <code>proxy_read_timeout</code>、CDN 边缘超时是否比后端处理时间短。</li><li>长任务改成异步任务 + 轮询 / 推送。</li></ul></li></ul><h2 id="追问-3-502-和-504-都指向「网关问题」-怎么区分" tabindex="-1">追问 3：502 和 504 都指向「网关问题」，怎么区分？ <a class="header-anchor" href="#追问-3-502-和-504-都指向「网关问题」-怎么区分" aria-label="Permalink to &quot;追问 3：502 和 504 都指向「网关问题」，怎么区分？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>502 Bad Gateway</strong>：网关收到了上游的响应，但<strong>响应不合法</strong>（连接被重置、返回内容错乱、TLS 握手失败、上游进程崩了）。</li><li><strong>504 Gateway Timeout</strong>：网关等上游响应<strong>超时</strong>，根本没收到有效响应。</li><li>排查： <ul><li>502：检查上游服务是否 crash / OOM / 端口未监听 / 反向代理配置错误；查看上游访问日志有无请求进来。</li><li>504：检查上游接口是否慢（数据库慢查询、下游依赖超时）；检查网关的 <code>proxy_read_timeout</code> / <code>upstream_response_timeout</code> 设置是否太短。</li></ul></li><li>客户端体验相似（都是 Bad Gateway 页面），但后端处理策略不同：502 常常需要修 bug / 重启，504 常常要优化性能或调整超时。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc9110.html" target="_blank" rel="noreferrer">RFC 9110: HTTP Semantics</a>：状态码定义与语义</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Status" target="_blank" rel="noreferrer">MDN: HTTP response status codes</a>：常用状态码速查</li><li><a href="https://www.iana.org/assignments/http-status-codes/http-status-codes.xhtml" target="_blank" rel="noreferrer">IANA HTTP Status Code Registry</a>：官方状态码注册表</li></ul>',32)])])}const h=o(i,[["render",a]]);export{c as __pageData,h as default};
